INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('aboriginal-f7485f85-moex-00101', 'aboriginal-f7485f85', 'aboriginal-f7485f85-moex-112-6ed013db', 'sub-aboriginal-f7485f85-05', NULL, 'single_choice', '依憲法訴訟法規定，下列何者為國家最高機關聲請憲法法庭判決之要件？', '["行使職權，適用憲法，發生疑義", "經確定終局裁判", "經行政救濟程序所適用", "行使職權，就所適用之法規範，認有牴觸憲法"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:09+00:00", "source_pdf_sha1": "28a4987213d2", "answer_pdf_sha1": "e2b696b5ba2c", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "610", "s": "0219", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "外交行政人員"}'::jsonb, NULL),
  ('aboriginal-f7485f85-moex-00102', 'aboriginal-f7485f85', 'aboriginal-f7485f85-moex-112-6ed013db', 'sub-aboriginal-f7485f85-05', NULL, 'single_choice', '依司法院大法官解釋，地方制度法有關縣（市）議會正副議長選舉之規定，下列敘述何者錯誤？', '["有關縣（市）議會正副議長選舉以記名投票為之，違背憲法第129條所定各種選舉應以無記名投票 方法行之", "縣（市）議會正副議長之選舉，應有議員、代表總額過半數之出席，以得票達出席總數之過半數者 為當選", "縣（市）議會正副議長之選舉結果無人當選時，應立即舉行第二次投票，以得票較多者為當選；得 票相同者，以抽籤定之", "中央法律要求地方議會應以記名投票方式選舉議長、副議長，並不侵害地方自治"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:09+00:00", "source_pdf_sha1": "28a4987213d2", "answer_pdf_sha1": "e2b696b5ba2c", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "610", "s": "0219", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "外交行政人員"}'::jsonb, NULL),
  ('aboriginal-f7485f85-moex-00103', 'aboriginal-f7485f85', 'aboriginal-f7485f85-moex-112-6ed013db', 'sub-aboriginal-f7485f85-05', NULL, 'single_choice', '下列關於原住民族語言能力認證辦法之規定的敘述，何者正確？', '["本辦法之主管機關為教育部，族語能力認證工作由原住民族委員會負責辦理", "族語能力認證分為初級、中級、中高級、高級、優級及特優級", "參加族語能力認證者，不受國籍、族別及年齡之限制，但須從初級開始，逐級通過認證", "族語能力認證方式，包含測驗與審查"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:09+00:00", "source_pdf_sha1": "28a4987213d2", "answer_pdf_sha1": "e2b696b5ba2c", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "610", "s": "0219", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "外交行政人員"}'::jsonb, NULL),
  ('aboriginal-f7485f85-moex-00104', 'aboriginal-f7485f85', 'aboriginal-f7485f85-moex-112-6ed013db', 'sub-aboriginal-f7485f85-05', NULL, 'single_choice', '下列關於原住民族教育法之敘述，何者正確？', '["依據該法第4條的定義，一般教育係指為增加全國學生對於原住民族歷史文化之認識與素養提升， 所實施之教育", "依據該法第5條的規定，為發展及厚植原住民族知識體系，中央原住民族主管機關應會商教育、科 技、文化等主管機關，建構原住民族知識體系中長程計畫。前項中長程計畫，至少每3年通盤檢討 1次，並公告之", "依據該法第7條的規定，中央教育主管機關與中央原住民族主管機關應共同召開原住民族教育政策 會，進行包含原住民族教育體系、建構原住民族知識體系中長程計畫等原住民族教育政策之規劃、 制訂與審議", "依據該法第8條的規定，直轄市及所轄區域內有原住民族地區或原住民重點學校之縣（市），地方 政府應召開直轄市、縣（市）原住民族教育審議會，進行地方原住民族教育事項之審議"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:09+00:00", "source_pdf_sha1": "28a4987213d2", "answer_pdf_sha1": "e2b696b5ba2c", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "610", "s": "0219", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "外交行政人員"}'::jsonb, NULL),
  ('aboriginal-f7485f85-moex-00105', 'aboriginal-f7485f85', 'aboriginal-f7485f85-moex-112-6ed013db', 'sub-aboriginal-f7485f85-05', NULL, 'single_choice', '為辦理原住民族基本法第2條第4款所規定之部落核定作業，原住民族委員會訂有原住民族委員會辦 理部落核定作業要點。下列關於原住民族委員會辦理部落核定作業要點之規定的敘述，何者錯誤？', '["鄉（鎮、市）及區公所應依職權或轄內原住民之請求，邀集熟稔部落歷史文化之民眾，進行部落之 訪查及統計", "部落概況訪查表應載明之事項，包含人口數、戶數、家族、族別及其比例，也包含共同生活區域範圍", "鄉（鎮、市、區）公所完成部落之訪查及統計後，應依照原住民族委員會推動原住民族部落會議實 施要點舉辦部落會議，聽取族人意見，並應將部落概況訪查表公告於公所、村（里）辦公室及其他 原住民常出入之公開場所。公告期間不得少於30日", "鄉（鎮、市、區）公所公告期間屆滿時，如無須修正之內容時，鄉（鎮、市、區）公所應將公告內 容函送直轄市、縣（市）政府審查。經審查通過後，直轄市、縣（市）政府應於2週內將公告內容、 審查意見及審查會議紀錄函送原住民族委員會審核"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:09+00:00", "source_pdf_sha1": "28a4987213d2", "answer_pdf_sha1": "e2b696b5ba2c", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "610", "s": "0219", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "外交行政人員"}'::jsonb, NULL),
  ('aboriginal-f7485f85-moex-00106', 'aboriginal-f7485f85', 'aboriginal-f7485f85-moex-112-6ed013db', 'sub-aboriginal-f7485f85-05', NULL, 'single_choice', '依據諮商取得原住民族部落同意參與辦法附件，下列那一種行為不屬於原住民族基本法第21條所指 涉的開發行為？', '["礦產或土石之鑽探、採取工程及其碎解、洗選、冶煉、儲庫等其他增進產能設施之興建、增進產能 或擴建", "觀光（休閒）飯店及旅（賓）館之興建或擴建", "核能、水力、火力、風力、太陽光、溫差、地熱之發電機組、設備、電廠、汽電共生廠及其輸電線 路、超高壓變電所之設置、興建或擴建", "原住民於其所有之原住民保留地之所為，且對原住民族之居住或生活環境無不良影響之虞"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:09+00:00", "source_pdf_sha1": "28a4987213d2", "answer_pdf_sha1": "e2b696b5ba2c", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "610", "s": "0219", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "外交行政人員"}'::jsonb, NULL),
  ('aboriginal-f7485f85-moex-00107', 'aboriginal-f7485f85', 'aboriginal-f7485f85-moex-112-6ed013db', 'sub-aboriginal-f7485f85-05', NULL, 'single_choice', '原住民族委員會組織法是原住民族委員會之職掌以及重要職務設置的依據。請問，下列關於原住民族 委員會組織法中對委員會之委員的規範敘述，何者正確？', '["置委員17人至27人", "委員是由主任委員提請行政院院長就原住民族代表、有關機關代表及學者、專家派（聘）兼之", "委員中原住民族各族代表應至少1人，依聘用人員聘用條例聘用，其聘期隨主任委員異動而更易， 均為無給職", "委員應有三分之一以上人數具原住民族身分"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:09+00:00", "source_pdf_sha1": "28a4987213d2", "answer_pdf_sha1": "e2b696b5ba2c", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "610", "s": "0219", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "外交行政人員"}'::jsonb, NULL),
  ('aboriginal-f7485f85-moex-00108', 'aboriginal-f7485f85', 'aboriginal-f7485f85-moex-112-6ed013db', 'sub-aboriginal-f7485f85-05', NULL, 'single_choice', '下列關於原住民族基本法第2條所定義事項之敘述，何者錯誤？', '["原住民族：係指既存於臺灣而為國家管轄內之傳統民族，包括阿美族、泰雅族、排灣族、布農族、 卑南族、魯凱族、鄒族、賽夏族、雅美族、邵族、噶瑪蘭族、太魯閣族及其他自認為原住民族並經 中央原住民族主管機關報請行政院核定之民族", "原住民族地區：係指原住民傳統居住，具有原住民族歷史淵源及文化特色，經中央原住民族主管機 關報請行政院核定之地區", "部落：係指原住民於原住民族地區一定區域內，依其傳統規範共同生活結合而成之團體，經中央原 住民族主管機關報請行政院核定者", "原住民族土地：係指原住民族傳統領域土地及既有原住民保留地"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:09+00:00", "source_pdf_sha1": "28a4987213d2", "answer_pdf_sha1": "e2b696b5ba2c", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "610", "s": "0219", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "外交行政人員"}'::jsonb, NULL),
  ('aboriginal-f7485f85-moex-00109', 'aboriginal-f7485f85', 'aboriginal-f7485f85-moex-112-6ed013db', 'sub-aboriginal-f7485f85-05', NULL, 'single_choice', '下列何者概念，係指以原住民族知識體系為主，確保原住民族於健康照護領域中獲得公平、適當之健 康服務，使其身分或文化得到適足保障？', '["健康正義", "健康平等", "文化適當性", "文化安全"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:09+00:00", "source_pdf_sha1": "28a4987213d2", "answer_pdf_sha1": "e2b696b5ba2c", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "610", "s": "0219", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "外交行政人員"}'::jsonb, NULL),
  ('aboriginal-f7485f85-moex-00110', 'aboriginal-f7485f85', 'aboriginal-f7485f85-moex-112-6ed013db', 'sub-aboriginal-f7485f85-05', NULL, 'single_choice', '依據原住民族工作權保障法規定，各級政府應設置原住民合作社輔導小組，而下列何者非原住民合作 社輔導考核及獎勵辦法中所規定之原住民合作社輔導小組成員？', '["合作社主管機關代表", "原住民事務主管機關代表", "目的事業主管機關代表", "原住民族社會經濟與勞動文化相關之學者專家"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:09+00:00", "source_pdf_sha1": "28a4987213d2", "answer_pdf_sha1": "e2b696b5ba2c", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "610", "s": "0219", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "外交行政人員"}'::jsonb, NULL)
